using System.Collections;
using TMPro;
using UnityEngine;
using UnityEngine.EventSystems;
using UnityEngine.UI;

/// <summary>
/// Sub-painel "Créditos" do Menu Principal (Tarefa #39) — mostra os créditos
/// do jogo com scroll automático e possibilidade de saltar/fechar.
///
/// O conteúdo é um único TMP_Text (<see cref="creditsText"/>) cujo texto é
/// configurado no Inspector. O scroll é feito movendo <see cref="contentRoot"/>
/// para cima ao longo do tempo (velocidade <see cref="scrollSpeed"/>). Ao
/// chegar ao fim (ou ao pressionar Voltar/B/Escape), o scroll para e o painel
/// fecha.
///
/// Montagem no Editor:
/// - "root": GameObject raiz (escondido por defeito).
/// - "contentRoot": Transform movido para cima durante o scroll (filho de uma
///   Mask com Scroll Rect, ou simplesmente um RectTransform "solto").
/// - "creditsText": TMP_Text com todos os créditos.
/// - "skipButton"/"backButton": "Saltar" (vai directamente para o fim/fecha) e
///   "Voltar" (fecha imediatamente); podem ser o mesmo botão.
/// - "scrollSpeed": unidades UI por segundo (ex: 60).
/// - "endPauseSeconds": pausa no fim antes de fechar automaticamente (0 = não
///   fecha automaticamente — espera input do jogador).
/// </summary>
public class CreditosUI : MonoBehaviour, ICancelHandler
{
    [Header("Framework")]
    [SerializeField] private GameObject root;
    [SerializeField] private Button backButton;
    [SerializeField] private Button skipButton;

    [Header("Conteúdo")]
    [SerializeField] private RectTransform contentRoot;
    [SerializeField] private TMP_Text creditsText;

    [Tooltip("Texto dos créditos — preencher directamente no Inspector ou via script antes de Open().")]
    [TextArea(10, 40)]
    [SerializeField] private string creditsContent = "ANIMALS\n\nDesenvolvimento\n[Nome]\n\nArte\n[Nome]\n\nMúsica\n[Nome]\n\n...";

    [Header("Scroll")]
    [Tooltip("Velocidade de scroll automático em unidades UI por segundo.")]
    [SerializeField] private float scrollSpeed = 60f;

    [Tooltip("Segundos de pausa no fim antes de fechar automaticamente (0 = aguarda input).")]
    [SerializeField] private float endPauseSeconds = 3f;

    /// <summary>Disparado ao fechar o painel.</summary>
    public event System.Action Closed;

    public GameObject Root => root != null ? root : gameObject;

    private float _startY;
    private float _endY;
    private bool _scrolling;
    private Coroutine _scrollCoroutine;

    private void Awake()
    {
        if (backButton != null) backButton.onClick.AddListener(Close);
        if (skipButton != null) skipButton.onClick.AddListener(SkipToEnd);
        if (root != null) root.SetActive(false);
    }

    // ---------------- Abrir / Fechar ----------------

    public void Open()
    {
        if (root != null) root.SetActive(true);

        // Preenche o texto.
        if (creditsText != null)
        {
            creditsText.text = creditsContent;
            // Força rebuild para obter a altura correcta do conteúdo.
            Canvas.ForceUpdateCanvases();
        }

        ResetScroll();

        if (_scrollCoroutine != null) StopCoroutine(_scrollCoroutine);
        _scrollCoroutine = StartCoroutine(ScrollRoutine());
    }

    public void Close()
    {
        StopScrolling();
        if (root != null) root.SetActive(false);
        Closed?.Invoke();
    }

    public void OnCancel(BaseEventData eventData) => Close();

    // ---------------- Scroll ----------------

    private void ResetScroll()
    {
        if (contentRoot == null) return;

        // Posição inicial: conteúdo começa no topo (anchoredPosition.y == 0).
        var pos = contentRoot.anchoredPosition;
        pos.y = 0f;
        contentRoot.anchoredPosition = pos;

        _startY = 0f;
        // Altura total a percorrer: altura do conteúdo menos a altura do viewport.
        // Se não houver parent Mask/ScrollRect, usa apenas a altura do próprio conteúdo.
        float contentHeight = contentRoot.rect.height;
        float viewportHeight = contentRoot.parent is RectTransform vp ? vp.rect.height : 0f;
        _endY = Mathf.Max(0f, contentHeight - viewportHeight);
    }

    private IEnumerator ScrollRoutine()
    {
        _scrolling = true;

        while (_scrolling && contentRoot != null)
        {
            var pos = contentRoot.anchoredPosition;

            if (pos.y >= _endY)
            {
                // Chegou ao fim.
                _scrolling = false;
                break;
            }

            pos.y = Mathf.MoveTowards(pos.y, _endY, scrollSpeed * Time.unscaledDeltaTime);
            contentRoot.anchoredPosition = pos;

            yield return null;
        }

        // Pausa no fim antes de fechar (se configurado).
        if (endPauseSeconds > 0f)
        {
            yield return new WaitForSecondsRealtime(endPauseSeconds);
            Close();
        }
        // else: aguarda o jogador carregar em "Voltar".
    }

    private void SkipToEnd()
    {
        // Para o scroll e posiciona directamente no fim — o jogador ainda
        // precisa de carregar em "Voltar" para fechar (ou endPauseSeconds fecha).
        StopScrolling();

        if (contentRoot != null)
        {
            var pos = contentRoot.anchoredPosition;
            pos.y = _endY;
            contentRoot.anchoredPosition = pos;
        }

        if (endPauseSeconds > 0f)
        {
            if (_scrollCoroutine != null) StopCoroutine(_scrollCoroutine);
            _scrollCoroutine = StartCoroutine(CloseAfterPause());
        }
    }

    private IEnumerator CloseAfterPause()
    {
        yield return new WaitForSecondsRealtime(endPauseSeconds);
        Close();
    }

    private void StopScrolling()
    {
        _scrolling = false;
        if (_scrollCoroutine != null)
        {
            StopCoroutine(_scrollCoroutine);
            _scrollCoroutine = null;
        }
    }
}
